  `lastmodifiedon` datetime DEFAULT NULL,
  `prefix` varchar(50) DEFAULT NULL,
  `currentno` int(11) DEFAULT NULL,
  `rawmaterialcategory` tinyint(1) DEFAULT 0,
  PRIMARY KEY (`categoryid`),
  KEY `idx_categories_categoryid` (`categoryid`),
  KEY `idx_branch_category` (`clientid`),
  KEY `idx_categories_client` (`clientid`),
  CONSTRAINT `fk_categories_clients` FOREIGN KEY (`clientid`) REFERENCES `clients` (`clientid`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

