/*Table structure for table `clients` */

DROP TABLE IF EXISTS `clients`;

CREATE TABLE `clients` (
  `clientid` int(11) NOT NULL AUTO_INCREMENT,
  `client_name` varchar(100) NOT NULL,
  `subdomain` varchar(50) DEFAULT NULL,
  `packageid` int(11) DEFAULT NULL,
  `contact_person` varchar(100) DEFAULT NULL,
  `phone_number` varchar(20) DEFAULT NULL,
  `email` varchar(100) DEFAULT NULL,
  `physical_address` text DEFAULT NULL,
  `city` varchar(50) DEFAULT NULL,
  `country` varchar(50) DEFAULT NULL,
  `due_date` date DEFAULT NULL,
  `status` enum('active','inactive','suspended') DEFAULT 'active',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `branchid` int(11) DEFAULT 1,
  `postaladdress` varchar(100) DEFAULT NULL,
  `landline` varchar(50) DEFAULT NULL,
  `mobile` varchar(50) DEFAULT NULL,
  `pinno` varchar(50) DEFAULT NULL,
  `autoaddinvoiceduringgrn` tinyint(1) DEFAULT NULL,
  `postalcode` varchar(50) DEFAULT NULL,
  `quotationvalidity` int(11) DEFAULT 30,
  `tagline` varchar(1000) DEFAULT NULL,
  `website` varchar(100) DEFAULT NULL,
  `receiptfooter` varchar(4000) DEFAULT NULL,
  `defaultcustomer` int(11) DEFAULT NULL,
  `mainbusinesstype` varchar(50) DEFAULT NULL,
  `logo` varchar(1000) DEFAULT NULL,
  `showwaiterlogin` tinyint(1) DEFAULT 1,
  `town` varchar(50) DEFAULT NULL,
  `printreceipt` tinyint(4) DEFAULT 1,
  `sendtovault` tinyint(1) DEFAULT 0,
  `allow_price_change` tinyint(1) DEFAULT 0,
  `allow_negative_sales_globally` tinyint(1) DEFAULT 0,
  PRIMARY KEY (`clientid`),
  UNIQUE KEY `subdomain` (`subdomain`),
  KEY `fk_client_package` (`packageid`),
  CONSTRAINT `fk_client_package` FOREIGN KEY (`packageid`) REFERENCES `packages` (`packageid`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

