/*Table structure for table `cratesinventory` */

DROP TABLE IF EXISTS `cratesinventory`;

CREATE TABLE `cratesinventory` (
  `cratesinventoryid` int(11) NOT NULL AUTO_INCREMENT,
  `branchid` int(11) DEFAULT NULL,
  `productid` int(11) DEFAULT NULL,
  `quantity` decimal(18,2) DEFAULT NULL,
  `unitprice` decimal(18,2) DEFAULT NULL,
  `dateadded` datetime DEFAULT NULL,
  `narration` varchar(1000) DEFAULT NULL,
  `reference` varchar(50) DEFAULT NULL,
  `addedby` int(11) DEFAULT NULL,
  PRIMARY KEY (`cratesinventoryid`),
  KEY `productid` (`productid`),
  KEY `addedby` (`addedby`),
  CONSTRAINT `cratesinventory_ibfk_1` FOREIGN KEY (`productid`) REFERENCES `products_old` (`productid`),
  CONSTRAINT `cratesinventory_ibfk_2` FOREIGN KEY (`addedby`) REFERENCES `user` (`userid`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

/*Data for the table `cratesinventory` */

/*Table structure for table `cratesinventorysettings` */

DROP TABLE IF EXISTS `cratesinventorysettings`;

CREATE TABLE `cratesinventorysettings` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `productid` int(11) DEFAULT NULL,
  `supplierid` int(11) DEFAULT NULL,
  `glaccountid` int(11) DEFAULT NULL,
  `costcenterid` int(11) DEFAULT NULL,
  `paymentmode` int(11) DEFAULT NULL,
  `paymentaccount` int(11) DEFAULT NULL,
  `branchid` int(11) DEFAULT 1,
  PRIMARY KEY (`id`),
  KEY `productid` (`productid`),
  KEY `supplierid` (`supplierid`),
  KEY `glaccountid` (`glaccountid`),
  KEY `costcenterid` (`costcenterid`),
  KEY `paymentmode` (`paymentmode`),
  KEY `paymentaccount` (`paymentaccount`),
  CONSTRAINT `cratesinventorysettings_ibfk_1` FOREIGN KEY (`productid`) REFERENCES `products_old` (`productid`),
  CONSTRAINT `cratesinventorysettings_ibfk_2` FOREIGN KEY (`supplierid`) REFERENCES `suppliers` (`supplierid`),
  CONSTRAINT `cratesinventorysettings_ibfk_3` FOREIGN KEY (`glaccountid`) REFERENCES `glaccounts` (`id`),
  CONSTRAINT `cratesinventorysettings_ibfk_4` FOREIGN KEY (`costcenterid`) REFERENCES `pointsofsale` (`posid`),
  CONSTRAINT `cratesinventorysettings_ibfk_5` FOREIGN KEY (`paymentmode`) REFERENCES `paymentmethods` (`id`),
  CONSTRAINT `cratesinventorysettings_ibfk_6` FOREIGN KEY (`paymentaccount`) REFERENCES `glaccounts` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

/*Data for the table `cratesinventorysettings` */

/*Table structure for table `creditnotedetails` */

DROP TABLE IF EXISTS `creditnotedetails`;

CREATE TABLE `creditnotedetails` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `noteid` int(11) DEFAULT NULL,
  `itemcode` int(11) DEFAULT NULL,
  `quantity` decimal(10,0) DEFAULT NULL,
  `unitprice` decimal(10,0) DEFAULT NULL,
  `branchid` int(11) DEFAULT 1,
  PRIMARY KEY (`id`),
  KEY `noteid` (`noteid`),
  KEY `itemcode` (`itemcode`),
  CONSTRAINT `creditnotedetails_ibfk_1` FOREIGN KEY (`noteid`) REFERENCES `creditnotes` (`id`),
  CONSTRAINT `creditnotedetails_ibfk_2` FOREIGN KEY (`itemcode`) REFERENCES `products_old` (`productid`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

/*Data for the table `creditnotedetails` */

/*Table structure for table `creditnotes` */

DROP TABLE IF EXISTS `creditnotes`;

CREATE TABLE `creditnotes` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `noteno` varchar(50) DEFAULT NULL,
  `customerid` decimal(10,0) DEFAULT NULL,
  `dateadded` datetime DEFAULT NULL,
  `addedby` int(11) DEFAULT NULL,
  `used` bit(1) DEFAULT b'0',
  `possaleid` decimal(10,0) DEFAULT NULL,
  `branchid` int(11) DEFAULT 1,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

/*Data for the table `creditnotes` */

/*Table structure for table `currencies` */

DROP TABLE IF EXISTS `currencies`;

CREATE TABLE `currencies` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `currencyname` varchar(50) DEFAULT NULL,
  `symbol` varchar(3) DEFAULT NULL,
  `default` tinyint(1) DEFAULT 0,
  `clientid` int(11) DEFAULT 1,
  PRIMARY KEY (`id`),
  KEY `idx_currencies_client` (`clientid`),
  CONSTRAINT `fk_currencies_clients` FOREIGN KEY (`clientid`) REFERENCES `clients` (`clientid`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

/*Data for the table `currencies` */

