  `customercategoryid` int(11) DEFAULT NULL,
  `percentage` bit(1) DEFAULT NULL,
  `value` decimal(10,0) DEFAULT NULL,
  `branchid` int(11) DEFAULT 1,
  PRIMARY KEY (`id`),
  KEY `itemid` (`itemid`),
  KEY `customercategoryid` (`customercategoryid`),
  CONSTRAINT `customerpricematrix_ibfk_1` FOREIGN KEY (`itemid`) REFERENCES `products` (`productid`)
) ENGINE=InnoDB AUTO_INCREMENT=9 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

