  `customerid` int(11) DEFAULT NULL,
  `receiptdate` datetime DEFAULT NULL,
  `addedby` int(11) DEFAULT NULL,
  `modeofpayment` int(11) DEFAULT NULL,
  `referenceno` varchar(50) DEFAULT NULL,
  `deleted` tinyint(1) DEFAULT NULL,
  `reasondeleted` varchar(500) DEFAULT NULL,
  `deletedby` int(11) DEFAULT NULL,
  `lastmodifieddate` datetime DEFAULT NULL,
  `banked` tinyint(1) DEFAULT NULL,
  `bankingrefno` varchar(50) DEFAULT NULL,
  PRIMARY KEY (`customerreceiptid`),
  KEY `addedby` (`addedby`),
  KEY `modeofpayment` (`modeofpayment`),
  KEY `deletedby` (`deletedby`),
