  CONSTRAINT `customerreceipts_ibfk_1` FOREIGN KEY (`addedby`) REFERENCES `user` (`userid`),
  CONSTRAINT `customerreceipts_ibfk_2` FOREIGN KEY (`modeofpayment`) REFERENCES `paymentmethods` (`id`),
  CONSTRAINT `customerreceipts_ibfk_3` FOREIGN KEY (`deletedby`) REFERENCES `user` (`userid`),
  CONSTRAINT `customerreceipts_ibfk_4` FOREIGN KEY (`customerid`) REFERENCES `customers` (`customerid`)
