  `id` int(11) NOT NULL AUTO_INCREMENT,
  `showaiterlogin` tinyint(1) DEFAULT 0,
  `logo` varchar(1000) DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

/*Data for the table `loginuisettings` */

insert  into `loginuisettings`(`id`,`showaiterlogin`,`logo`) values 
(1,0,'images/logo.png');

/*Table structure for table `materialdetails` */

DROP TABLE IF EXISTS `materialdetails`;

CREATE TABLE `materialdetails` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `categoryid` int(11) DEFAULT NULL,
  `itemcode` varchar(50) DEFAULT NULL,
  `description` varchar(50) DEFAULT NULL,
  `dateadded` datetime DEFAULT NULL,
  `addedby` int(11) DEFAULT NULL,
  `unitofmeasureid` int(11) DEFAULT NULL,
  `indexed` tinyint(1) DEFAULT NULL,
  `deleted` tinyint(1) NOT NULL DEFAULT 0,
  `datedeleted` datetime DEFAULT NULL,
  `deletedby` int(11) DEFAULT NULL,
  `buyingprice` decimal(18,2) DEFAULT NULL,
  `sellingprice` decimal(18,2) DEFAULT NULL,
  `narration` varchar(1000) DEFAULT NULL,
  `inventoryitem` tinyint(1) DEFAULT NULL,
  `reorderlevel` decimal(18,2) DEFAULT NULL,
  `branchid` int(11) DEFAULT 1,
  PRIMARY KEY (`id`,`deleted`),
  UNIQUE KEY `itemcode` (`itemcode`),
  KEY `categoryid` (`categoryid`),
  KEY `unitofmeasureid` (`unitofmeasureid`),
  KEY `materialdetails_ibfk_2` (`addedby`),
  KEY `deletedby` (`deletedby`)
) ENGINE=InnoDB AUTO_INCREMENT=2883 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

/*Data for the table `materialdetails` */

