/*Table structure for table `papergrammage` */

DROP TABLE IF EXISTS `papergrammage`;

CREATE TABLE `papergrammage` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `grammage` varchar(50) DEFAULT NULL,
  `branchid` int(11) DEFAULT 1,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

/*Data for the table `papergrammage` */

insert  into `papergrammage`(`id`,`grammage`,`branchid`) values 
(1,'100',1),
(2,'150',1),
(3,'200',1);

/*Table structure for table `paymentmethods` */

DROP TABLE IF EXISTS `paymentmethods`;

CREATE TABLE `paymentmethods` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `clientid` int(11) DEFAULT 1,
  `description` varchar(50) DEFAULT NULL,
  `requiresrefno` tinyint(4) DEFAULT NULL,
  `image` longblob DEFAULT NULL,
  `supplierslist` tinyint(1) DEFAULT 0,
  `show` tinyint(1) DEFAULT 1,
  `default` tinyint(1) NOT NULL DEFAULT 0,
  `branchid` int(11) DEFAULT 1,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=9 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

