/*Table structure for table `paymentvoucherdetails` */

DROP TABLE IF EXISTS `paymentvoucherdetails`;

CREATE TABLE `paymentvoucherdetails` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `clientid` int(11) DEFAULT 1,
  `voucherid` int(11) DEFAULT NULL,
  `itemcode` varchar(50) DEFAULT NULL,
  `description` varchar(500) DEFAULT NULL,
  `quantity` decimal(10,3) DEFAULT NULL,
  `unitprice` decimal(10,3) DEFAULT NULL,
  `accountcharged` int(11) DEFAULT NULL,
  `invoicenumber` varchar(50) DEFAULT NULL,
  `branchid` int(11) DEFAULT 1,
  PRIMARY KEY (`id`),
  KEY `voucherid` (`voucherid`),
  KEY `clientid` (`clientid`)
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

/*Data for the table `paymentvoucherdetails` */

insert  into `paymentvoucherdetails`(`id`,`clientid`,`voucherid`,`itemcode`,`description`,`quantity`,`unitprice`,`accountcharged`,`invoicenumber`,`branchid`) values 
(1,1,1,'ITEM001','Test Voucher Item 1',2.000,150.000,1,'INV-999',1);

/*Table structure for table `paymentvouchers` */

DROP TABLE IF EXISTS `paymentvouchers`;

CREATE TABLE `paymentvouchers` (
  `paymentvoucherid` int(11) NOT NULL AUTO_INCREMENT,
  `clientid` int(11) DEFAULT 1,
  `branchid` int(11) DEFAULT NULL,
  `voucherno` varchar(50) DEFAULT NULL,
  `date` datetime DEFAULT NULL,
  `dateadded` datetime DEFAULT NULL,
  `addedby` int(11) DEFAULT NULL,
  `paymentmode` int(11) DEFAULT NULL,
  `pos` int(11) DEFAULT NULL,
  `supplier` int(11) DEFAULT NULL,
  `cashbookaccount` int(11) DEFAULT NULL,
  `referenceno` varchar(50) DEFAULT NULL,
  `status` varchar(50) DEFAULT NULL,
  `lastmodifiedby` int(11) DEFAULT NULL,
  `lastmodifieddate` datetime DEFAULT NULL,
  `reasoncancelled` varchar(500) DEFAULT NULL,
  `pettycashvoucher` tinyint(1) DEFAULT 0,
  PRIMARY KEY (`paymentvoucherid`),
  KEY `addedby` (`addedby`),
  KEY `pos` (`pos`),
  KEY `paymentmode` (`paymentmode`),
  KEY `supplier` (`supplier`),
  KEY `lastmodifiedby` (`lastmodifiedby`),
  KEY `clientid` (`clientid`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

/*Data for the table `paymentvouchers` */

insert  into `paymentvouchers`(`paymentvoucherid`,`clientid`,`branchid`,`voucherno`,`date`,`dateadded`,`addedby`,`paymentmode`,`pos`,`supplier`,`cashbookaccount`,`referenceno`,`status`,`lastmodifiedby`,`lastmodifieddate`,`reasoncancelled`,`pettycashvoucher`) values 
(1,1,1,'PV-000001','2026-06-04 16:10:00','2026-06-04 17:10:00',1,1,1,1,1,'REF-123','Pending',NULL,NULL,NULL,1);

/*Table structure for table `pointsofsale` */

DROP TABLE IF EXISTS `pointsofsale`;

CREATE TABLE `pointsofsale` (
  `posid` int(11) NOT NULL AUTO_INCREMENT,
  `clientid` int(11) DEFAULT 1,
  `branchid` int(11) DEFAULT NULL,
  `posname` varchar(50) DEFAULT NULL,
  `dateadded` datetime DEFAULT NULL,
  `addedby` decimal(10,0) DEFAULT NULL,
  `deleted` tinyint(1) DEFAULT 0,
  `lastdatemodified` datetime DEFAULT NULL,
  `lastmodifiedby` decimal(10,0) DEFAULT NULL,
  `default` tinyint(1) DEFAULT NULL,
  `postype` varchar(50) DEFAULT NULL COMMENT 'Either restaurant or retail',
  `printkitchenorders` tinyint(1) DEFAULT 0,
  PRIMARY KEY (`posid`),
  KEY `idx_pointsofsale_id_posname` (`posid`,`posname`)
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

