/*Table structure for table `possales` */

DROP TABLE IF EXISTS `possales`;

CREATE TABLE `possales` (
  `possaleid` int(11) NOT NULL AUTO_INCREMENT,
  `branchid` int(11) DEFAULT NULL,
  `sessionid` int(11) DEFAULT NULL,
  `receiptno` varchar(50) DEFAULT NULL,
  `receiptdate` datetime DEFAULT NULL,
  `customerid` int(11) DEFAULT NULL,
  `pointofsaleid` int(11) DEFAULT NULL,
  `addedby` int(11) DEFAULT NULL,
  `deleted` tinyint(1) DEFAULT 0,
  `deletedon` datetime DEFAULT NULL,
  `deletedby` int(11) DEFAULT NULL,
  `reason` varchar(50) DEFAULT NULL,
  `printed` tinyint(1) DEFAULT 0,
  `timestamp` timestamp NULL DEFAULT current_timestamp(),
  `reference` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  PRIMARY KEY (`possaleid`),
  KEY `customerid` (`customerid`),
  KEY `pointofsaleid` (`pointofsaleid`),
  KEY `addedby` (`addedby`),
  KEY `idx_possales_receiptdate` (`receiptdate`),
  KEY `idx_possales_id_pointofsaleid_receiptdate_deleted` (`possaleid`,`pointofsaleid`,`receiptdate`,`deleted`),
  KEY `idx_possales_date_deleted_posid` (`receiptdate`,`deleted`,`pointofsaleid`),
  KEY `idx_branch_sale` (`branchid`)
) ENGINE=InnoDB AUTO_INCREMENT=34 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

/*Data for the table `possales` */

