/*Table structure for table `possalesdetails` */

DROP TABLE IF EXISTS `possalesdetails`;

CREATE TABLE `possalesdetails` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `possaleid` int(11) DEFAULT NULL,
  `itemcode` int(11) DEFAULT NULL,
  `quantity` decimal(10,2) DEFAULT NULL,
  `unitprice` decimal(10,2) DEFAULT NULL,
  `discount` decimal(10,2) DEFAULT NULL,
  `serialno` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `taxtypeid` int(11) DEFAULT NULL,
  `taxrate` decimal(18,2) DEFAULT NULL,
  `description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `branchid` int(11) DEFAULT 1,
  `uom` varchar(50) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `possaleid` (`possaleid`),
  KEY `itemcode` (`itemcode`),
  KEY `idx_possalesdetails_possaleid` (`possaleid`),
  KEY `idx_possalesdetails_itemcode_possaleid` (`itemcode`,`possaleid`),
  KEY `idx_possalesdetails_possaleid_itemcode` (`possaleid`,`itemcode`),
  KEY `idx_possalesdetails_saleid_itemcode` (`possaleid`,`itemcode`)
) ENGINE=InnoDB AUTO_INCREMENT=142 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

