/*Table structure for table `products` */

DROP TABLE IF EXISTS `products`;

CREATE TABLE `products` (
  `productid` int(11) NOT NULL AUTO_INCREMENT,
  `clientid` int(11) DEFAULT 1,
  `itemcode` varchar(50) NOT NULL,
  `itemname` varchar(255) DEFAULT NULL,
  `unitofmeasure` varchar(50) DEFAULT NULL,
  `buyingprice` decimal(10,2) DEFAULT NULL,
  `sellingprice` decimal(10,2) DEFAULT NULL,
  `categoryid` int(11) DEFAULT NULL,
  `dateadded` datetime DEFAULT NULL,
  `addedby` int(11) DEFAULT NULL,
  `deleted` tinyint(1) DEFAULT 0,
  `reorderlevel` decimal(10,0) DEFAULT 5,
  `lastmodifiedon` datetime DEFAULT NULL,
  `lastmodifiedby` int(11) DEFAULT NULL,
  `wholesaleprice` decimal(10,2) DEFAULT NULL,
  `serializable` tinyint(1) DEFAULT 0,
  `bundleitem` tinyint(1) DEFAULT 0,
  `taxtypeid` int(11) DEFAULT NULL,
  `length` decimal(18,2) DEFAULT 0.00,
  `width` decimal(18,2) DEFAULT 0.00,
  `height` decimal(18,2) DEFAULT 0.00,
  `allownegativesales` tinyint(1) DEFAULT 0,
  `saleby` varchar(50) DEFAULT 'quantity',
  `bundledproduct` int(11) DEFAULT NULL,
  `allowreturnexchange` tinyint(1) DEFAULT 0,
  `rawmaterial` tinyint(1) DEFAULT 0,
  `itemtype` varchar(50) DEFAULT 'product',
  `disallowpurchasing` tinyint(1) DEFAULT 0,
  `disallowreceipt` tinyint(1) DEFAULT 0,
  `disallowsale` tinyint(1) DEFAULT 0,
  PRIMARY KEY (`productid`),
  KEY `productid` (`productid`),
  KEY `categoryid` (`categoryid`),
  KEY `addedby` (`addedby`),
  KEY `idx_products_categoryid` (`categoryid`),
  KEY `idx_products_categoryid_productid` (`categoryid`,`productid`),
  KEY `idx_branch_product` (`clientid`),
  KEY `idx_products_client` (`clientid`),
  CONSTRAINT `fk_products_clients` FOREIGN KEY (`clientid`) REFERENCES `clients` (`clientid`)
) ENGINE=InnoDB AUTO_INCREMENT=48 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

