/*Table structure for table `products_old` */

DROP TABLE IF EXISTS `products_old`;

CREATE TABLE `products_old` (
  `productid` int(11) NOT NULL AUTO_INCREMENT,
  `itemcode` varchar(50) NOT NULL,
  `itemname` varchar(50) DEFAULT NULL,
  `unitofmeasure` varchar(50) DEFAULT NULL,
  `buyingprice` decimal(10,2) DEFAULT NULL,
  `sellingprice` decimal(10,2) DEFAULT NULL,
  `categoryid` int(11) DEFAULT NULL,
  `dateadded` datetime DEFAULT NULL,
  `addedby` int(11) DEFAULT NULL,
  `deleted` tinyint(1) DEFAULT 0,
  `reorderlevel` decimal(10,0) DEFAULT NULL,
  `lastmodifiedon` datetime DEFAULT NULL,
  `lastmodifiedby` int(11) DEFAULT NULL,
  `wholesaleprice` decimal(10,2) DEFAULT NULL,
  `serializable` tinyint(1) DEFAULT NULL,
  `bundleitem` tinyint(1) DEFAULT NULL,
  `taxtypeid` int(11) DEFAULT NULL,
  `length` decimal(18,2) DEFAULT NULL,
  `width` decimal(18,2) DEFAULT NULL,
  `height` decimal(18,2) DEFAULT NULL,
  `allownegativesales` tinyint(1) DEFAULT 0,
  `saleby` varchar(50) DEFAULT 'quantity',
  `branchid` int(11) DEFAULT 1,
  PRIMARY KEY (`productid`),
  KEY `productid` (`productid`),
  KEY `categoryid` (`categoryid`),
  KEY `addedby` (`addedby`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

