/*Table structure for table `quotation` */

DROP TABLE IF EXISTS `quotation`;

CREATE TABLE `quotation` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `quoteno` varchar(50) DEFAULT NULL,
  `quotedate` datetime DEFAULT NULL,
  `terms` varchar(1000) DEFAULT NULL,
  `customerid` int(11) DEFAULT NULL,
  `expirydate` datetime DEFAULT NULL,
  `addedby` int(11) DEFAULT NULL,
  `deleted` tinyint(1) DEFAULT NULL,
  `datedeleted` datetime DEFAULT NULL,
  `deletedby` int(11) DEFAULT NULL,
  `status` varchar(50) DEFAULT 'Valid',
  `category` varchar(50) DEFAULT NULL,
  `branchid` int(11) DEFAULT 1,
  PRIMARY KEY (`id`),
  KEY `customerid` (`customerid`),
  KEY `addedby` (`addedby`),
  KEY `deletedby` (`deletedby`)
) ENGINE=InnoDB AUTO_INCREMENT=11 DEFAULT CHARSET=utf8 COLLATE=utf8_general_ci;

/*Data for the table `quotation` */

/*Table structure for table `quotationapproval` */

DROP TABLE IF EXISTS `quotationapproval`;

CREATE TABLE `quotationapproval` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `quoteid` int(11) DEFAULT NULL,
  `userid` int(11) DEFAULT NULL,
  `approvallevelid` int(11) DEFAULT NULL,
  `approvaldate` datetime DEFAULT NULL,
  `narration` varchar(1000) DEFAULT NULL,
  `branchid` int(11) DEFAULT 1,
  PRIMARY KEY (`id`),
  KEY `quoteid` (`quoteid`),
  KEY `userid` (`userid`),
  KEY `approvallevelid` (`approvallevelid`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

/*Data for the table `quotationapproval` */

/*Table structure for table `quotationapprovallevels` */

DROP TABLE IF EXISTS `quotationapprovallevels`;

CREATE TABLE `quotationapprovallevels` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `description` varchar(50) DEFAULT NULL,
  `hierarchy` int(11) DEFAULT NULL,
  `deleted` tinyint(1) DEFAULT 0,
  `dateadded` datetime DEFAULT NULL,
  `addedby` int(11) DEFAULT NULL,
  `deletedby` int(11) DEFAULT NULL,
  `datedeleted` datetime DEFAULT NULL,
  `branchid` int(11) DEFAULT 1,
  PRIMARY KEY (`id`),
  KEY `addedby` (`addedby`),
  KEY `deletedby` (`deletedby`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

/*Data for the table `quotationapprovallevels` */

/*Table structure for table `quotationapprovalusers` */

DROP TABLE IF EXISTS `quotationapprovalusers`;

CREATE TABLE `quotationapprovalusers` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `approvallevelid` int(11) DEFAULT NULL,
  `userid` int(11) DEFAULT NULL,
  `valid` tinyint(1) DEFAULT 1,
  `addedby` int(11) DEFAULT NULL,
  `dateadded` datetime DEFAULT NULL,
  `invalidateddate` datetime DEFAULT NULL,
  `invalidatedby` int(11) DEFAULT NULL,
  `branchid` int(11) DEFAULT 1,
  PRIMARY KEY (`id`),
  KEY `approvallevelid` (`approvallevelid`),
  KEY `userid` (`userid`),
  KEY `addedby` (`addedby`),
  KEY `invalidatedby` (`invalidatedby`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

/*Data for the table `quotationapprovalusers` */

/*Table structure for table `quotationdetails` */

DROP TABLE IF EXISTS `quotationdetails`;

CREATE TABLE `quotationdetails` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `quoteid` int(11) DEFAULT NULL,
  `itemid` int(11) DEFAULT NULL,
  `description` varchar(500) DEFAULT NULL,
  `quantity` decimal(18,2) DEFAULT NULL,
  `unitprice` decimal(18,2) DEFAULT NULL,
  `length` decimal(18,2) DEFAULT 0.00,
  `width` decimal(18,2) DEFAULT 0.00,
  `height` decimal(18,2) DEFAULT NULL,
  `gsm` decimal(18,2) DEFAULT NULL,
  `weight` decimal(18,4) DEFAULT NULL,
  `plies` decimal(18,2) DEFAULT NULL,
  `jointallowance` decimal(18,2) DEFAULT NULL,
  `trimallowance` decimal(18,2) DEFAULT NULL,
  `profitmargin` decimal(18,2) DEFAULT NULL,
  `printing` decimal(18,2) DEFAULT NULL,
  `freight` decimal(18,2) DEFAULT NULL,
  `waste` decimal(18,2) DEFAULT NULL,
  `flutefactor` decimal(18,2) DEFAULT NULL,
  `branchid` int(11) DEFAULT 1,
  PRIMARY KEY (`id`),
  KEY `quoteid` (`quoteid`),
  KEY `itemid` (`itemid`)
) ENGINE=InnoDB AUTO_INCREMENT=23 DEFAULT CHARSET=utf8 COLLATE=utf8_general_ci;

