/* Function  structure for function  `fngeneratecreditnoteno` */

/*!50003 DROP FUNCTION IF EXISTS `fngeneratecreditnoteno` */;
DELIMITER $$

/*!50003 CREATE DEFINER=`root`@`localhost` FUNCTION `fngeneratecreditnoteno`() RETURNS varchar(50) CHARSET latin1 COLLATE latin1_swedish_ci
BEGIN
	DECLARE $grnno VARCHAR(50);
	SET $grnno=(SELECT CONCAT(
		`prefix`,
		CASE CHAR_LENGTH(`currentno`) 
			WHEN 1 THEN '0000'
			WHEN 2 THEN '000'
			WHEN 3 THEN '00'
			WHEN 4 THEN '0'
			ELSE '' 
		END,
		`currentno`) FROM `serials` WHERE `documenttype`='Credit Note');
	RETURN $grnno;
    END */$$
DELIMITER ;

/* Function  structure for function  `fngeneratecustomercreditrefno` */

/*!50003 DROP FUNCTION IF EXISTS `fngeneratecustomercreditrefno` */;
DELIMITER $$

/*!50003 CREATE DEFINER=`root`@`localhost` FUNCTION `fngeneratecustomercreditrefno`() RETURNS varchar(50) CHARSET latin1 COLLATE latin1_swedish_ci
BEGIN
	DECLARE $receiptno VARCHAR(50);
	SET $receiptno=(SELECT CONCAT(
		`prefix`,
		CASE CHAR_LENGTH(`currentno`) 
			WHEN 1 THEN '0000'
			WHEN 2 THEN '000'
			WHEN 3 THEN '00'
			WHEN 4 THEN '0'
			ELSE '' 
		END,
		`currentno`) FROM `serials` WHERE `documenttype`='Credit Sale');
	RETURN $receiptno;
    END */$$
DELIMITER ;

/* Function  structure for function  `fngeneratecustomerno` */

/*!50003 DROP FUNCTION IF EXISTS `fngeneratecustomerno` */;
DELIMITER $$

/*!50003 CREATE DEFINER=`root`@`localhost` FUNCTION `fngeneratecustomerno`(p_branchid INT) RETURNS varchar(50) CHARSET latin1 COLLATE latin1_swedish_ci
BEGIN
    DECLARE v_customerno VARCHAR(50);
    SET v_customerno = (SELECT CONCAT(
        `prefix`,
        CASE CHAR_LENGTH(`currentno`) 
            WHEN 1 THEN '0000'
            WHEN 2 THEN '000'
            WHEN 3 THEN '00'
            WHEN 4 THEN '0'
            ELSE '' 
        END,
        `currentno`) FROM `serials` WHERE branchid = p_branchid AND `documenttype` = 'Customer Number');
    RETURN v_customerno;
END */$$
DELIMITER ;

/* Function  structure for function  `fngenerategrnno` */

/*!50003 DROP FUNCTION IF EXISTS `fngenerategrnno` */;
DELIMITER $$

/*!50003 CREATE DEFINER=`root`@`localhost` FUNCTION `fngenerategrnno`(p_branchid INT) RETURNS varchar(50) CHARSET latin1 COLLATE latin1_swedish_ci
