/* Function  structure for function  `fngenerateproductcode` */

/*!50003 DROP FUNCTION IF EXISTS `fngenerateproductcode` */;
DELIMITER $$

/*!50003 CREATE DEFINER=`root`@`localhost` FUNCTION `fngenerateproductcode`(p_clientid INT, p_categoryid NUMERIC) RETURNS varchar(50) CHARSET latin1 COLLATE latin1_swedish_ci
BEGIN
    DECLARE v_itemcode VARCHAR(50);
    SET v_itemcode = (SELECT CONCAT(
        `prefix`,
        CASE CHAR_LENGTH(`currentno`) 
            WHEN 1 THEN '0000'
            WHEN 2 THEN '000'
            WHEN 3 THEN '00'
            WHEN 4 THEN '0'
            ELSE '' 
        END,
        `currentno`) FROM `categories` WHERE `clientid` = p_clientid AND `categoryid` = p_categoryid);
    RETURN v_itemcode;
END */$$
DELIMITER ;

