DELIMITER $$

/*!50003 CREATE DEFINER=`root`@`localhost` FUNCTION `fn_receiptpaymentmodes`(`$receiptno` VARCHAR(50)) RETURNS varchar(4000) CHARSET latin1 COLLATE latin1_swedish_ci
BEGIN
	DECLARE v_finished INTEGER DEFAULT 0;
