DELIMITER $$

/*!50003 CREATE DEFINER=`root`@`localhost` PROCEDURE `savetemppurchaseorderdetails`(`$refno` VARCHAR(50), `$itemcode` VARCHAR(50), `$quantity` NUMERIC, `$unitprice` NUMERIC)
BEGIN
