/* Procedure structure for procedure `spgetcustomerdetails` */

/*!50003 DROP PROCEDURE IF EXISTS  `spgetcustomerdetails` */;

DELIMITER $$

/*!50003 CREATE DEFINER=`root`@`localhost` PROCEDURE `spgetcustomerdetails`(IN $clientid INT, IN $customerid INT)
BEGIN
