	AND s.`grnno`=sd.`grnno` AND sd.`itemcode`=p.productid AND p.productid=r.`productid` AND r.`grnid`=s.id
	AND DATE_FORMAT(r.`dateadded`,'%Y-%m-%d') BETWEEN $startdate AND $enddate
