/* Procedure structure for procedure `spmergeanddeleteproduct` */

/*!50003 DROP PROCEDURE IF EXISTS  `spmergeanddeleteproduct` */;

DELIMITER $$

/*!50003 CREATE DEFINER=`root`@`localhost` PROCEDURE `spmergeanddeleteproduct`(
    IN $clientid INT,
    IN $source_id INT,
    IN $target_id INT,
    IN $userid INT
)
BEGIN
    START TRANSACTION;
    
    -- 1. Update all transaction tables referencing the product
    UPDATE possalesdetails SET itemcode = $target_id WHERE itemcode = $source_id;
    UPDATE goodsreceiveddetails SET itemcode = $target_id WHERE itemcode = $source_id;
    UPDATE stocktransferdetails SET itemcode = $target_id WHERE itemcode = $source_id;
    UPDATE stockreconciledbalancedetails SET itemid = $target_id WHERE itemid = $source_id;
    UPDATE spoilage SET productid = $target_id WHERE productid = $source_id;
    UPDATE purchaseorderdetails SET itemcode = $target_id WHERE itemcode = $source_id;
    UPDATE heldsalesdetails SET productid = $target_id WHERE productid = $source_id;
    UPDATE cratesinventory SET productid = $target_id WHERE productid = $source_id;
    UPDATE stockmovement SET productid = $target_id WHERE productid = $source_id;
    
    -- 2. Update metadata/relationship tables
    UPDATE productpricehistory SET productid = $target_id WHERE productid = $source_id;
    UPDATE productsplitunits SET productid = $target_id WHERE productid = $source_id;
    UPDATE productrecipes SET productid = $target_id WHERE productid = $source_id;
    UPDATE productrecipes SET recipeitemid = $target_id WHERE recipeitemid = $source_id;
    UPDATE supplierproducts SET productid = $target_id WHERE productid = $source_id;
    UPDATE tempstocktransfer SET itemcode = $target_id WHERE itemcode = $source_id;
    UPDATE tempstockreconcilebalancedetails SET itemid = $target_id WHERE itemid = $source_id;
    
    -- 3. Mark the source product as deleted
    UPDATE products SET deleted = 1, lastmodifiedon = NOW(), lastmodifiedby = $userid 
    WHERE clientid = $clientid AND productid = $source_id;
    
    COMMIT;
END */$$
DELIMITER ;

/* Procedure structure for procedure `sppostbanking` */

/*!50003 DROP PROCEDURE IF EXISTS  `sppostbanking` */;

DELIMITER $$

/*!50003 CREATE DEFINER=`root`@`localhost` PROCEDURE `sppostbanking`(
        IN `$branchid` INT,
        IN `$refno` VARCHAR(50),
        IN `$cashbookaccount` INT,
        IN `$narration` VARCHAR(50),
        IN `$reference` VARCHAR(50),
        IN `$postas` VARCHAR(50),
        IN `$userid` INT,
        IN `$receiptbanked` VARCHAR(50)
    )
BEGIN
        DECLARE $salesaccount INT;
        DECLARE $transactiondate DATETIME;
        DECLARE $debtorscontrolaccount INT;
        SET $transactiondate = NOW();
        
        SET $salesaccount = (SELECT id FROM glaccounts WHERE accountcode = (SELECT `account` FROM `glaccountsettings` WHERE description = "Sales"));
        SET $debtorscontrolaccount = (SELECT id FROM glaccounts WHERE accountcode = (SELECT `account` FROM `glaccountsettings` WHERE description = "Debtors Control Account"));
        
        START TRANSACTION;
            -- post to sales or debtors control account individual transactions
            IF $receiptbanked != "pos" THEN
                SET $salesaccount = $debtorscontrolaccount;
            END IF;
            
            INSERT INTO `gltransactions`(`branchid`, `referenceno`, `transactiondate`, `glaccount`, `glcontraaccount`, `narration`, `debit`, `credit`, `addedby`)
            SELECT $branchid, $reference, $transactiondate, $salesaccount, $cashbookaccount,
                CONCAT("Banking of receipt # ", `receiptno`, " of reference #", `reference`, " issued to ", `customername`, " (", $narration, ")"),
                0, `amount`, $userid 
            FROM `tempbanking` 
            WHERE `refno` = $refno;
            
            -- post to the cashbook account
            IF $postas = "single" THEN		
                INSERT INTO `gltransactions` (`branchid`, `referenceno`, `transactiondate`, `glaccount`, `glcontraaccount`, `narration`, `debit`, `credit`, `addedby`)
                SELECT $branchid, $reference, $transactiondate, $cashbookaccount, $salesaccount, 
                    CONCAT("Banking of receipt # ", `receiptno`, " of reference #", `reference`, " issued to ", `customername`, " (", $narration, ")"),
                    amount, 0, $userid 
                FROM `tempbanking` 
                WHERE `refno` = $refno; 
            ELSE
                INSERT INTO `gltransactions` (`branchid`, `referenceno`, `transactiondate`, `glaccount`, `glcontraaccount`, `narration`, `debit`, `credit`, `addedby`)
                SELECT $branchid, $reference, $transactiondate, $cashbookaccount, $salesaccount, $narration, 
                    SUM(amount), 0, $userid 
                FROM `tempbanking` 
                WHERE `refno` = $refno 
                GROUP BY `refno`; 
            END IF;
            
            -- update all receipts
            IF $receiptbanked = "pos" THEN 
                UPDATE `possalespayments` p, `tempbanking` b  
                SET p.`banked` = 1, p.`bankingreference` = $reference 
                WHERE b.`id` = p.id;
            ELSE
                UPDATE `customerreceipts` p, `tempbanking` b 
                SET `banked` = 1, `bankingrefno` = $reference
                WHERE b.`id` = p.id;
            END IF;
            
            -- remove temp data 
            DELETE FROM `tempbanking` WHERE `refno` = $refno;
        COMMIT;
    END */$$
DELIMITER ;

/* Procedure structure for procedure `spsaceglgroupname` */

/*!50003 DROP PROCEDURE IF EXISTS  `spsaceglgroupname` */;

DELIMITER $$

/*!50003 CREATE DEFINER=`root`@`localhost` PROCEDURE `spsaceglgroupname`(`$id` INT, `$glaccountclass` INT, `$groupname` VARCHAR(50), `$subcategoryof` INT, `$cashbookaccount` INT, `$clientid` INT)
BEGIN
	IF $id=0 THEN
		INSERT INTO `glaccountgroups`(`groupname`,`subactegoryof`,`dateadded`,`addedby`,`deleted`,`cashbookaccount`,`glaccountclass`)
		VALUES($groupname,$subcategoryof,NOW(),$clientid,0,$cashbookaccount,$glaccountclass);
	ELSE
		UPDATE `glaccountgroups` SET `groupname`=$groupname,`subactegoryof`=$subcategoryof,`cashbookaccount`=$cashbookaccouont,
		`glaccountclass`=$glaccountclass,`lastupdatedby`=$clientid, `lastdateupdated`=NOW()
		WHERE id=$id;
	END IF;
    END */$$
DELIMITER ;

/* Procedure structure for procedure `spsavecategory` */

/*!50003 DROP PROCEDURE IF EXISTS  `spsavecategory` */;

DELIMITER $$

/*!50003 CREATE DEFINER=`root`@`localhost` PROCEDURE `spsavecategory`(IN $clientid INT, IN $id INT, IN $name VARCHAR(50),
    IN $prefix VARCHAR(50),
    IN $currentno INT,
    IN $userid INT
)
BEGIN
    IF $id = 0 THEN
        INSERT INTO `categories` (clientid, `categoryname`, `prefix`, `currentno`, `dateadded`, `addedby`, `deleted`)
        VALUES (clientid, $name, $prefix, $currentno, NOW(), $userid, 0);
    ELSE
        UPDATE `categories` SET 
            `categoryname` = $name, `prefix` = $prefix, `currentno` = $currentno, 
            `lastmodifiedon` = NOW(), `lastmodifiedby` = $userid
        WHERE clientid = $clientid AND `categoryid` = $id;
    END IF;
END */$$
DELIMITER ;

/* Procedure structure for procedure `spsavecity` */

/*!50003 DROP PROCEDURE IF EXISTS  `spsavecity` */;

DELIMITER $$

/*!50003 CREATE DEFINER=`root`@`localhost` PROCEDURE `spsavecity`(
    IN $cityid INT,
    IN $cityname VARCHAR(100),
    IN $countryid INT
)
BEGIN
    IF $cityid = 0 THEN
        INSERT INTO cities (cityname, countryid)
        VALUES ($cityname, $countryid);
    ELSE
        UPDATE cities SET 
            cityname = $cityname,
            countryid = $countryid
        WHERE cityid = $cityid;
    END IF;
END */$$
