/*!50003 CREATE DEFINER=`root`@`localhost` PROCEDURE `spsaveglaccount`(
                IN $branchid INT, 
                IN $id INT, 
                IN $groupid INT, 
                IN $accountcode VARCHAR(50), 
                IN $accountname VARCHAR(50), 
                IN $clientid INT
            )
