                IF $id = 0 THEN 
                    INSERT INTO `glaccounts`(`groupid`,`accountcode`,`accountname`,`dateadded`,`addedby`,`deleted`,`clientid`)
                    VALUES($groupid,$accountcode,$accountname,NOW(),$clientid,0,$branchid);
                ELSE
                    UPDATE `glaccounts` 
                    SET `groupid` = $groupid, 
                        `accountcode` = $accountcode, 
