/*!50003 CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_savefleetvehicle`(`$vehicleid` INT, `$regno` VARCHAR(50), `$bodytypeid` INT, `$fueltypeid` INT, `$enginerating` INT, `$clientid` INT)
BEGIN
