/*!50003 CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_saveinstitutiondetails`(
    IN $clientid INT,
    IN $companyname VARCHAR(100),
    IN $physicaladdress TEXT,
    IN $postaladdress VARCHAR(100),
