/*!50003 CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_saverawmaterial`(`$materialid` INT, `$categoryid` INT, `$materialname` VARCHAR(50), `$uom` VARCHAR(50), `$physicalproduct` BOOL, `$unitprice` DECIMAL(18,2), `$itemcode` VARCHAR(50), `$generateitemcode` BOOL, `$clientid` INT)
