DELIMITER $$

/*!50003 CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_savetempquotation`(`$refno` VARCHAR(50), `$itemid` INT, `$description` VARCHAR(500), `$quantity` DECIMAL(18,2), `$unitprice` DECIMAL(18,2), `$ilength` DECIMAL(18,2), `$width` DECIMAL(18,2), `$height` DECIMAL(18,2), `$gsm` DECIMAL(18,2), `$weight` DECIMAL(18,4), `$plies` DECIMAL(18,2), `$jointallowance` DECIMAL(18,2), `$trimallowance` DECIMAL(18,2), `$profitmargin` DECIMAL(18,2), `$printing` DECIMAL(18,2), `$freight` DECIMAL(18,2), `$waste` DECIMAL(18,2), `$flutefactor` DECIMAL(18,2))
