/*View structure for view vwcustomerreceipts */

/*!50001 DROP TABLE IF EXISTS `vwcustomerreceipts` */;
/*!50001 DROP VIEW IF EXISTS `vwcustomerreceipts` */;

/*!50001 CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vwcustomerreceipts` AS select `r`.`customerreceiptid` AS `id`,date_format(`r`.`receiptdate`,'%Y-%m-%d') AS `date`,`o`.`posname` AS `posname`,`c`.`customername` AS `customername`,`r`.`receiptno` AS `receiptno`,`r`.`modeofpayment` AS `paymentmodeid`,`p`.`description` AS `description`,`r`.`referenceno` AS `reference`,ifnull(`r`.`banked`,0) AS `banked`,sum(`rd`.`amount`) AS `amount`,concat(`u`.`firstname`,' ',`u`.`lastname`) AS `addedby` from (((((`customerreceipts` `r` join `customerreceiptdetails` `rd` on(`r`.`customerreceiptid` = `rd`.`receiptid`)) join `customers` `c` on(`r`.`customerid` = `c`.`customerid`)) join `paymentmethods` `p` on(`r`.`modeofpayment` = `p`.`id`)) join `pointsofsale` `o` on(`c`.`posid` = `o`.`posid`)) join `user` `u` on(`r`.`addedby` = `u`.`userid`)) where ifnull(`r`.`deleted`,0) = 0 group by `r`.`customerreceiptid`,`o`.`posname`,`c`.`customername`,`r`.`receiptno`,`r`.`modeofpayment`,`p`.`description`,`r`.`referenceno`,`r`.`banked`,`u`.`firstname`,`u`.`lastname`,`r`.`receiptdate` order by date_format(`r`.`receiptdate`,'%Y-%m-%d') */;

/*View structure for view vwcustomerstomerstatement */

/*!50001 DROP TABLE IF EXISTS `vwcustomerstomerstatement` */;
/*!50001 DROP VIEW IF EXISTS `vwcustomerstomerstatement` */;

/*!50001 CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vwcustomerstomerstatement` AS select `p`.`branchid` AS `branchid`,`p`.`possaleid` AS `id`,`c`.`customerid` AS `customerid`,`c`.`customername` AS `customername`,`c`.`physicaladdress` AS `physicaladdress`,`c`.`postaladdress` AS `postaladdress`,`c`.`mobile` AS `mobile`,`c`.`email` AS `email`,`p`.`receiptdate` AS `date`,'Invoice issued to customer' AS `narration`,`pm`.`reference` AS `reference`,`pm`.`amount` AS `invoiceamount`,0 AS `invoicepayment`,0 AS `order` from ((`customers` `c` join `possales` `p` on(`c`.`customerid` = `p`.`customerid`)) join `possalespayments` `pm` on(`p`.`possaleid` = `pm`.`possaleid`)) where `pm`.`paymentmode` = 4 and `p`.`deleted` = 0 and cast(`p`.`receiptdate` as date) >= (select cast(`startingparameters`.`cutoffdate` as date) from `startingparameters` limit 1) union all select `cr`.`branchid` AS `branchid`,`cr`.`customerreceiptid` AS `id`,`c`.`customerid` AS `customerid`,`c`.`customername` AS `customername`,`c`.`physicaladdress` AS `physicaladdress`,`c`.`postaladdress` AS `postaladdress`,`c`.`mobile` AS `mobile`,`c`.`email` AS `email`,`cr`.`receiptdate` AS `date`,'Payment received. Thank You' AS `narration`,`cr`.`receiptno` AS `reference`,0 AS `invoiceamount`,sum(`cd`.`amount`) AS `invoicepayment`,1 AS `order` from ((`customers` `c` join `customerreceipts` `cr` on(`c`.`customerid` = `cr`.`customerid`)) join `customerreceiptdetails` `cd` on(`cr`.`customerreceiptid` = `cd`.`receiptid`)) where (`cr`.`deleted` is null or `cr`.`deleted` = 0) and cast(`cr`.`receiptdate` as date) >= (select cast(`startingparameters`.`cutoffdate` as date) from `startingparameters` limit 1) group by `cr`.`branchid`,`cr`.`customerreceiptid`,`c`.`customerid`,`cr`.`receiptdate`,`cr`.`receiptno` */;

