/*!50001 CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vwstockdetails` AS select date_format(`p`.`receiptdate`,'%d-%b-%Y') AS `date`,`s`.`posname` AS `posname`,`m`.`itemcode` AS `itemcode`,`m`.`itemname` AS `itemname`,`m`.`unitofmeasure` AS `unitofmeasure`,`m`.`buyingprice` AS `buyingprice`,avg(`pd`.`unitprice`) AS `sellingprice`,0 AS `purchases`,sum(`pd`.`quantity`) AS `quantitysold`,ifnull((select sum(`std`.`quantity`) from (`stocktransfer` `st` join `stocktransferdetails` `std` on(`st`.`stocktransferid` = `std`.`transferid`)) where `std`.`itemcode` = `pd`.`itemcode` and `st`.`sourcetype` = 'pos' and `st`.`sourceid` = `s`.`posid` and date_format(`st`.`dateadded`,'%d-%b-%Y') = date_format(`p`.`receiptdate`,'%d-%b-%Y')),0) AS `transfersout`,ifnull((select sum(`std`.`quantity`) from (`stocktransfer` `st` join `stocktransferdetails` `std` on(`st`.`stocktransferid` = `std`.`transferid`)) where `std`.`itemcode` = `pd`.`itemcode` and `st`.`destinationtype` = 'pos' and `st`.`destinationid` = `s`.`posid` and date_format(`st`.`dateadded`,'%d-%b-%Y') = date_format(`p`.`receiptdate`,'%d-%b-%Y')),0) AS `transfersin` from (((`products` `m` join `possalesdetails` `pd` on(`m`.`productid` = `pd`.`itemcode`)) join `possales` `p` on(`p`.`possaleid` = `pd`.`possaleid`)) join `pointsofsale` `s` on(`p`.`pointofsaleid` = `s`.`posid`)) group by date_format(`p`.`receiptdate`,'%d-%b-%Y'),`s`.`posname`,`m`.`itemcode`,`m`.`itemname`,`m`.`unitofmeasure`,`m`.`buyingprice` union all select date_format(`p`.`datereceived`,'%d-%b-%Y') AS `date`,`s`.`description` AS `posname`,`m`.`itemcode` AS `itemcode`,`m`.`itemname` AS `itemname`,`m`.`unitofmeasure` AS `unitofmeasure`,ifnull((select avg(`xd`.`unitprice`) from (`purchaseorders` `x` join `purchaseorderdetails` `xd` on(`x`.`purchaseorderid` = `xd`.`purchaseorderid`)) where `x`.`purchaseorderno` = `pd`.`purchaseorderno`),0) AS `buyingprice`,`m`.`sellingprice` AS `sellingprice`,sum(`pd`.`quantity`) AS `purchases`,0 AS `quantitysold`,ifnull((select sum(`std`.`quantity`) from (`stocktransfer` `st` join `stocktransferdetails` `std` on(`st`.`stocktransferid` = `std`.`transferid`)) where `std`.`itemcode` = `pd`.`itemcode` and `st`.`sourcetype` = 'warehouse' and `st`.`sourceid` = `s`.`id` and date_format(`st`.`dateadded`,'%d-%b-%Y') = date_format(`p`.`datereceived`,'%d-%b-%Y')),0) AS `transfersout`,ifnull((select sum(`std`.`quantity`) from (`stocktransfer` `st` join `stocktransferdetails` `std` on(`st`.`stocktransferid` = `std`.`transferid`)) where `std`.`itemcode` = `pd`.`itemcode` and `st`.`destinationtype` = 'warehouse' and `st`.`destinationid` = `s`.`id` and date_format(`st`.`dateadded`,'%d-%b-%Y') = date_format(`p`.`datereceived`,'%d-%b-%Y')),0) AS `transfersin` from (((`products` `m` join `goodsreceiveddetails` `pd` on(`m`.`productid` = `pd`.`itemcode`)) join `goodsreceived` `p` on(`p`.`grnno` = `pd`.`grnno`)) join `warehouses` `s` on(`p`.`warehouseid` = `s`.`id`)) group by date_format(`p`.`datereceived`,'%d-%b-%Y'),`s`.`description`,`m`.`itemcode`,`m`.`itemname`,`m`.`unitofmeasure`,`m`.`buyingprice`,`m`.`sellingprice`,`pd`.`purchaseorderno` */;

